    # Open and extract tar file safely
    with tarfile.open(tar_path, 'r:*') as tar:
        # Validate all members before extraction to prevent path traversal
        for member in tar.getmembers():
            # Resolve the full path where the member would be extracted
            member_path = (destination_dir / member.name).resolve()
            
